('ph-internet', NULL, 1, 'phase', NULL, NULL, NULL, 'Internet Fundamentals', 'How the internet, web, DNS, HTTP, browsers, hosting, and TLS work.', 'Phase grouping for Internet Fundamentals.', 'trunk', 'roadmap-main', 1, 1, NULL, NULL, 100, 500, 520, '{"source":"roadmap.sh/backend","nodeKey":"ph-internet"}'::jsonb, true, false, '["Internet Fundamentals"]'::jsonb, '["Required child topics are completed"]'::jsonb),
