('internet-how-it-works', 'grp-internet-core', 1, 'topic', NULL, NULL, NULL, 'How the Internet Works', 'Understand clients, servers, routers, packets, IP addresses, and request paths.', 'How the Internet Works is a concrete backend roadmap topic.', 'choice', 'grp-internet-core-topics', 1, 1, 2, 'beginner', 80, 330, 240, '{"source":"roadmap.sh/backend","nodeKey":"internet-how-it-works"}'::jsonb, true, true, '["Explain How the Internet Works","Apply How the Internet Works in backend development"]'::jsonb, '["Can answer practical questions about How the Internet Works","Can use How the Internet Works in a small backend task"]'::jsonb),
