-- ============================================================
-- backend-roadmap-sh-full-detailed-seed.sql
-- Full detailed Backend Developer roadmap seed based on roadmap.sh/backend.
-- Includes dense skills, learning resources, video/course resources,
-- roadmap phases, choice groups, topic nodes, optional practice projects,
-- a small number of required milestone projects, mappings, and edges.
--
-- Progress design:
-- - phase and choice_group nodes are not trackable; they are computed.
-- - most mini-projects are optional recommendation/project nodes.
-- - only milestone projects are required, so project work strengthens the path
--   without making every phase project mandatory.
--
-- Re-runnable/idempotent for this roadmap slug.
-- ============================================================

-- Shared-skill aliases normalized against core/shared-skills.seed.sql.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- Ensure temp seed tables from a previous failed run do not block reruns in the same SQL session.
DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

-- ------------------------------------------------------------
-- Clean previous copy of this specific roadmap only.
-- ------------------------------------------------------------
DELETE FROM public.progress_event
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Backend Developer Roadmap - roadmap.sh Full Detailed Seed', 'Backend Developer Roadmap')
);

DELETE FROM public.user_node_progress
WHERE roadmap_enrollment_id IN (
    SELECT e.roadmap_enrollment_id
    FROM public.roadmap_enrollment e
    JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Backend Developer Roadmap - roadmap.sh Full Detailed Seed', 'Backend Developer Roadmap')
);

DELETE FROM public.roadmap_enrollment
WHERE roadmap_version_id IN (
    SELECT rv.roadmap_version_id
    FROM public.roadmap_version rv
    JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
    WHERE r.title IN ('Backend Developer Roadmap - roadmap.sh Full Detailed Seed', 'Backend Developer Roadmap')
);

DELETE FROM public.roadmap
WHERE title IN (
    'Backend Developer Roadmap - roadmap.sh Full Detailed Seed',
    'Backend Developer Roadmap'
);

-- ------------------------------------------------------------
-- Career role and roadmap/version.
-- ------------------------------------------------------------
VALUES (
    'Backend Developer',
    'backend-developer',
    'Backend developer path covering internet fundamentals, backend languages, databases, APIs, security, testing, architecture, containers, messaging, observability, scale, and DevOps awareness.',
    'Software Engineering',
    true
)
ON CONFLICT (slug) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    is_active = true,
    updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (
    SELECT career_role_id FROM public.career_role WHERE slug = 'backend-developer'
), inserted_roadmap AS (
    SELECT
        career_role_id,
        'Backend Developer Roadmap',
        'A structured learning path for becoming a backend developer, covering web fundamentals, backend programming, databases, API design, authentication, security, testing, deployment, architecture, observability, and production-ready system design.',
        'template',
        'static',
        'public'
    FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
    SELECT
        roadmap_id,
        1,
        'published',
        'Backend Developer Roadmap v1',
        'A practical backend development roadmap that moves from fundamentals to production readiness through phases, guided topics, checkpoints, optional practice projects, and required milestone projects.',
        360,
        'none',
        '{"source":"roadmap.sh/backend","version":"v1","projectPolicy":"practice projects are optional; milestone projects are required","estimatedHoursBasis":"representative required path, not every optional branch"}'::jsonb,
        'TB',
        'manual',
        now()
    FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
)
SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- ------------------------------------------------------------
-- Skills.
-- Shared skills are seeded by ../core/shared-skills.seed.sql.
-- Roadmap files only insert roadmap-specific skills and do not overwrite existing shared skills.
-- ------------------------------------------------------------
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;


SELECT ss.name, ss.slug, ss.category, ss.description, true
FROM seed_skill ss
WHERE NOT EXISTS (
    SELECT 1
    FROM public.skill s
    WHERE s.slug = ss.slug OR s.name = ss.name
);

-- ------------------------------------------------------------
-- Learning resources.
-- ------------------------------------------------------------
DROP TABLE IF EXISTS seed_resource;
CREATE TEMP TABLE seed_resource (resource_key text PRIMARY KEY, title text NOT NULL, url text NOT NULL, resource_type text NOT NULL, description text NOT NULL, provider text, difficulty_level text) ON COMMIT DROP;


SELECT sr.title, sr.url, sr.resource_type, sr.description, sr.provider, sr.difficulty_level, 'en', 'verified'
FROM seed_resource sr
WHERE NOT EXISTS (
    SELECT 1 FROM public.learning_resource lr WHERE lr.url = sr.url
);

-- ------------------------------------------------------------
-- Roadmap nodes.
-- ------------------------------------------------------------
DROP TABLE IF EXISTS seed_node;
CREATE TEMP TABLE seed_node (
    node_id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    node_key text UNIQUE NOT NULL,
    parent_key text,
    order_index int NOT NULL,
    node_type text NOT NULL,
    checkpoint_type text,
    selection_type text,
    required_count int,
    title text NOT NULL,
    description text,
    reason text,
    layout_role text NOT NULL,
    layout_group text,
    layout_rank int,
    layout_order int NOT NULL,
    estimated_hours int,
    difficulty_level text,
    priority int NOT NULL,
    position_x numeric(10,2),
    position_y numeric(10,2),
    metadata jsonb NOT NULL,
    is_required boolean NOT NULL,
    is_trackable boolean NOT NULL,
    learning_outcomes jsonb NOT NULL,
    completion_criteria jsonb NOT NULL
) ON COMMIT DROP;


SELECT
    sn.node_id,
    m.roadmap_version_id,
    parent.node_id,
    sn.node_key,
    sn.node_type,
    sn.checkpoint_type,
    sn.selection_type,
    sn.required_count,
    sn.title,
    sn.description,
    sn.reason,
    sn.order_index,
    sn.layout_role,
    sn.layout_group,
    sn.layout_rank,
    sn.layout_order,
    sn.estimated_hours,
    sn.difficulty_level,
    sn.priority,
    sn.position_x,
    sn.position_y,
    sn.metadata,
    sn.is_required,
    sn.is_trackable,
    sn.learning_outcomes,
    sn.completion_criteria
FROM seed_node sn
CROSS JOIN seed_roadmap_map m
LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET
    parent_node_id = EXCLUDED.parent_node_id,
    node_type = EXCLUDED.node_type,
    checkpoint_type = EXCLUDED.checkpoint_type,
    selection_type = EXCLUDED.selection_type,
    required_count = EXCLUDED.required_count,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    reason = EXCLUDED.reason,
    order_index = EXCLUDED.order_index,
    layout_role = EXCLUDED.layout_role,
    layout_group = EXCLUDED.layout_group,
    layout_rank = EXCLUDED.layout_rank,
    layout_order = EXCLUDED.layout_order,
    estimated_hours = EXCLUDED.estimated_hours,
    difficulty_level = EXCLUDED.difficulty_level,
    priority = EXCLUDED.priority,
    position_x = EXCLUDED.position_x,
    position_y = EXCLUDED.position_y,
    metadata = EXCLUDED.metadata,
    is_required = EXCLUDED.is_required,
    is_trackable = EXCLUDED.is_trackable,
    learning_outcomes = EXCLUDED.learning_outcomes,
    completion_criteria = EXCLUDED.completion_criteria;

-- ------------------------------------------------------------
-- Node-skill mappings.
-- ------------------------------------------------------------
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (node_key text NOT NULL, skill_slug text NOT NULL) ON COMMIT DROP;


SELECT DISTINCT rn.roadmap_node_id, s.skill_id
FROM seed_node_skill sns
JOIN seed_node sn ON sn.node_key = sns.node_key
JOIN seed_roadmap_map m ON true
JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = sn.node_key
JOIN public.skill s ON s.slug = sns.skill_slug
ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

-- ------------------------------------------------------------
-- Node-resource mappings.
-- ------------------------------------------------------------
DROP TABLE IF EXISTS seed_node_resource;
CREATE TEMP TABLE seed_node_resource (node_key text NOT NULL, resource_key text NOT NULL, order_index int NOT NULL) ON COMMIT DROP;


SELECT DISTINCT rn.roadmap_node_id, lr.learning_resource_id, snr.order_index, snr.order_index = 1
FROM seed_node_resource snr
JOIN seed_node sn ON sn.node_key = snr.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN seed_roadmap_map m ON true
JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = sn.node_key
JOIN public.learning_resource lr ON lr.url = sr.url
ON CONFLICT (roadmap_node_id, learning_resource_id) DO UPDATE SET
    order_index = EXCLUDED.order_index,
    is_primary = EXCLUDED.is_primary;

SELECT DISTINCT lr.learning_resource_id, s.skill_id
FROM seed_node_resource snr
JOIN seed_node_skill sns ON sns.node_key = snr.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN public.learning_resource lr ON lr.url = sr.url
JOIN public.skill s ON s.slug = sns.skill_slug
ON CONFLICT (learning_resource_id, skill_id) DO NOTHING;

-- ------------------------------------------------------------
-- Edges.
-- ------------------------------------------------------------
-- Visual edge rules follow roadmap-node-edge-progress-model.md:
--   sequence: main trunk phase-to-phase flow only.
--   contains: parent phase/group owns direct child nodes, including gates and projects.
--   choice: choice_group owns options/topics.
--   dependency/unlock/recommendation: logic/hints only, hidden by default.
-- Gates are checkpoint children of a phase, not standalone trunk nodes.
DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (from_key text NOT NULL, to_key text NOT NULL, edge_type text NOT NULL, dependency_type text NOT NULL, condition jsonb NOT NULL) ON COMMIT DROP;


-- Rebuild edges for this roadmap version so older visual edge mistakes do not remain after reruns.
DELETE FROM public.roadmap_edge e
USING seed_roadmap_map m
WHERE e.roadmap_version_id = m.roadmap_version_id;

SELECT
    m.roadmap_version_id,
    source.roadmap_node_id,
    target.roadmap_node_id,
    CASE
        -- Spec rule: sequence is the main roadmap trunk. Keep it only for phase/trunk nodes.
        WHEN se.edge_type = 'sequence'
             AND source.node_type = 'phase'
             AND target.node_type = 'phase'
            THEN 'sequence'

        -- Spec rule: contains is the parent-child structure. Any direct parent ownership should stay visible.
        WHEN target.parent_node_id = source.roadmap_node_id
             AND se.edge_type IN ('contains', 'recommendation', 'dependency', 'sequence', 'unlock')
            THEN 'contains'

        -- Spec rule: choice connects a choice_group to its options/topics.
        WHEN se.edge_type = 'choice'
             AND source.node_type = 'choice_group'
            THEN 'choice'

        -- Non-trunk sequence edges are semantic prerequisites, not visual blue lines.
        WHEN se.edge_type = 'sequence'
             AND se.dependency_type = 'recommended'
            THEN 'recommendation'

        WHEN se.edge_type = 'sequence'
            THEN 'dependency'

        -- Advanced edges stay available for backend logic but hidden by default in the UI.
        ELSE se.edge_type
    END AS edge_type,
    se.dependency_type,
    se.condition || jsonb_build_object(
        'isVisual',
        CASE
            WHEN se.edge_type = 'sequence'
                 AND source.node_type = 'phase'
                 AND target.node_type = 'phase'
                THEN true
            WHEN target.parent_node_id = source.roadmap_node_id
                 AND se.edge_type IN ('contains', 'recommendation', 'dependency', 'sequence', 'unlock')
                THEN true
            WHEN se.edge_type = 'choice'
                 AND source.node_type = 'choice_group'
                THEN true
            ELSE false
        END,
        'visualRule',
        CASE
            WHEN se.edge_type = 'sequence'
                 AND source.node_type = 'phase'
                 AND target.node_type = 'phase'
                THEN 'main_trunk_sequence'
            WHEN target.parent_node_id = source.roadmap_node_id
                 AND se.edge_type IN ('contains', 'recommendation', 'dependency', 'sequence', 'unlock')
                THEN 'parent_child_contains'
            WHEN se.edge_type = 'choice'
                 AND source.node_type = 'choice_group'
                THEN 'choice_group_branch'
            ELSE 'hidden_advanced_edge'
        END
    ) AS condition
FROM seed_edge se
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node source ON source.roadmap_version_id = m.roadmap_version_id AND source.slug = se.from_key
JOIN public.roadmap_node target ON target.roadmap_version_id = m.roadmap_version_id AND target.slug = se.to_key
ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET
    dependency_type = EXCLUDED.dependency_type,
    condition = EXCLUDED.condition;

-- Add missing direct phase-to-phase sequence edges when an older seed modeled a checkpoint
-- as sitting between phases. Checkpoints remain phase children; the phase sequence stays clean.
SELECT
    m.roadmap_version_id,
    source_phase.roadmap_node_id,
    target_phase.roadmap_node_id,
    'sequence',
    'required',
    jsonb_build_object(
        'rule', 'phase_sequence',
        'isVisual', true,
        'visualRule', 'main_trunk_sequence',
        'source', 'spec_cleanup'
    )
FROM seed_edge first_edge
CROSS JOIN seed_roadmap_map m
JOIN public.roadmap_node source_phase
    ON source_phase.roadmap_version_id = m.roadmap_version_id
   AND source_phase.slug = first_edge.from_key
JOIN public.roadmap_node checkpoint
    ON checkpoint.roadmap_version_id = m.roadmap_version_id
   AND checkpoint.slug = first_edge.to_key
JOIN seed_edge second_edge
    ON second_edge.from_key = first_edge.to_key
JOIN public.roadmap_node target_phase
    ON target_phase.roadmap_version_id = m.roadmap_version_id
   AND target_phase.slug = second_edge.to_key
WHERE first_edge.edge_type = 'sequence'
  AND second_edge.edge_type = 'sequence'
  AND source_phase.node_type = 'phase'
  AND checkpoint.node_type = 'checkpoint'
  AND target_phase.node_type = 'phase'
ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET
    dependency_type = EXCLUDED.dependency_type,
    condition = EXCLUDED.condition;
-- ------------------------------------------------------------
-- Seed summary.
-- Skills: 158
-- Learning resources: 181
-- Roadmap nodes: 174
-- Node-skill mappings: 337
-- Node-resource mappings: 359
-- Edges: 289
-- Edge rendering policy: follows roadmap-node-edge-progress-model.md.
-- Render by default: sequence, contains, choice.
-- Hide by default: dependency, unlock, recommendation.
-- Sequence edges are phase/trunk flow only; parent-child structure uses contains; choice groups use choice.
-- ------------------------------------------------------------

COMMIT;
